using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    // ── ChargeAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -10m));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // ── RefundAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ThrowsInvalidOperationException()
    {
        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.RefundAsync("ch_does_not_exist"));
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ThrowsInvalidOperationException()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75m);
        await _gateway.RefundAsync(charge.ChargeId);

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.RefundAsync(charge.ChargeId));
    }
}

